import React, { useEffect, useState } from 'react';
import api from '../api';

const PatientList = () => {
  const [patients, setPatients] = useState<any[]>([]);
  const [formData, setFormData] = useState({ first_name: '', last_name: '', date_of_birth: '', gender: 'Male', contact_number: '', email: '' });
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editData, setEditData] = useState<any>(null);

  const fetchPatients = () => {
    api.get('patients/').then((res: any) => setPatients(res.data));
  };

  useEffect(() => { fetchPatients(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('patients/', formData);
      setFormData({ first_name: '', last_name: '', date_of_birth: '', gender: 'Male', contact_number: '', email: '' });
      fetchPatients();
    } catch (err: any) { console.error("Add Error:", err.response?.data); }
  };

  const handleUpdate = async (id: number) => {
    try {
      // Gi-send ang tibuok 'editData' para dili mag-error ang required fields
      await api.put(`patients/${id}/`, editData);
      setEditingId(null);
      fetchPatients();
    } catch (err: any) { console.error("Update Error:", err.response?.data); }
  };

  return (
    <div className="p-4 space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-2 md:grid-cols-3 gap-2 bg-green-50 p-4 rounded">
        <input className="border p-2 rounded" placeholder="First Name" value={formData.first_name} onChange={e => setFormData({...formData, first_name: e.target.value})} required />
        <input className="border p-2 rounded" placeholder="Last Name" value={formData.last_name} onChange={e => setFormData({...formData, last_name: e.target.value})} required />
        <input className="border p-2 rounded" type="date" value={formData.date_of_birth} onChange={e => setFormData({...formData, date_of_birth: e.target.value})} required />
        <input className="border p-2 rounded" placeholder="Contact #" value={formData.contact_number} onChange={e => setFormData({...formData, contact_number: e.target.value})} required />
        <input className="border p-2 rounded" type="email" placeholder="Email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} required />
        <button type="submit" className="bg-green-600 text-white rounded">Register</button>
      </form>
      <table className="min-w-full bg-white border">
        <thead><tr className="bg-gray-100"><th>Name</th><th>Contact</th><th>Actions</th></tr></thead>
        <tbody>
          {patients.map((p: any) => (
            <tr key={p.patient_id} className="border-b">
              {editingId === p.patient_id ? (
                <>
                  <td><input className="border p-1 w-full" value={editData.first_name} onChange={e => setEditData({...editData, first_name: e.target.value})} /></td>
                  <td><input className="border p-1 w-full" value={editData.contact_number} onChange={e => setEditData({...editData, contact_number: e.target.value})} /></td>
                  <td className="p-2"><button onClick={() => handleUpdate(p.patient_id)} className="text-green-600">Save</button></td>
                </>
              ) : (
                <>
                  <td className="p-2">{p.first_name} {p.last_name}</td>
                  <td className="p-2">{p.contact_number}</td>
                  <td className="p-2 space-x-2 text-center">
                    <button onClick={() => { setEditingId(p.patient_id); setEditData(p); }} className="text-blue-600">Edit</button>
                    <button onClick={() => api.delete(`patients/${p.patient_id}/`).then(fetchPatients)} className="text-red-600">Delete</button>
                  </td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default PatientList;
